import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Encoding user input using ESAPI
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);

        // Displaying the encoded user input on a web page
        String output = "<div>" + encodedInput + "</div>";
        System.out.println(output);
    }
}

